UPDATE ibs.T1_FUND_TXN_EMP_RELA
SET CLAIM_STATUS_ID='2'
, VERIFY_DT=#{current_time}
, VERIFY_EMP_ID=#{user_id}     
, REMARK=CONCAT(COALESCE(REMARK,''),'审批时间',#{current_time1},'审批工号',#{user_id},'审批理由页面批复通过。')                     
WHERE TXN_NO=@{p_vuch} AND TXN_DT=@{p_txn_dt} AND EMP_ID=@{p_emp_id} AND CLAIM_STATUS_ID='1' ;

UPDATE ibs.T1_FUND_CST_EMP_RELA
SET CLAIM_STATUS_ID='2'
, VERIFY_DT=#{current_time}
, VERIFY_EMP_ID=#{user_id}     
, REMARK=CONCAT(COALESCE(REMARK,''),'审批时间',#{current_time1},'审批工号',#{user_id},'审批理由页面批复通过。')                     
WHERE IDENTN_NO=@{p_vuch} AND EMP_ID=@{p_emp_id} AND TXN_DT=@{p_txn_dt}  AND CLAIM_STATUS_ID='1';

UPDATE ibs.T1_FUND_DT_EMP_RELA
SET CLAIM_STATUS_ID='2'
, VERIFY_DT=#{current_time}
, VERIFY_EMP_ID=#{user_id}     
, REMARK=CONCAT(COALESCE(REMARK,''),'审批时间',#{current_time1},'审批工号',#{user_id},'审批理由页面批复通过。')                     
WHERE SERIAL_NO=@{p_vuch} AND EMP_ID=@{p_emp_id} AND TXN_DT=@{p_txn_dt}  AND CLAIM_STATUS_ID='1';

format.value:

String btnsh_ztCls="cls-button2";
String btnUnsh_ztCls="cls-button2";

String btnsh_ztEvent="if(confirm('提交后数据将不能修改，是否确认提交?')){invokeComponentSqlActionButton('claim_fund_verify','select','button1',{p_vuch:'"+VUCH_NO+"', p_emp_id:'"+EMP_ID+"', p_txn_dt:'"+TXN_DT+"'},true,refreshPage)}";
String btnUnsh_ztEvent="wx_winpage('ShowReport.wx?PAGEID=claim_fund_vfy_no&VUCH_NO="+VUCH_NO+"&EMP_ID="+EMP_ID+"&TXN_DT="+TXN_DT+"',{width:550,height:350});art.dialog.close();";

sh_zt_btn="<input type=\"button\" class=\""+btnsh_ztCls+"\" value=\"通过\" onclick=\""+btnsh_ztEvent+"\">";
sh_zt_btn=sh_zt_btn+"<input type=\"button\" class=\""+btnUnsh_ztCls+"\" value=\"不通过\"   onclick=\""+btnUnsh_ztEvent+"\">";

