UPDATE ibs.T1_FUND_TXN_EMP_RELA
SET CLAIM_STATUS_ID='3'
, VERIFY_DT=#{current_time}
, VERIFY_EMP_ID=#{user_id}     
, REMARK1=@{REMARK1}
, REMARK=CONCAT(COALESCE(REMARK,''),'审批时间',#{current_time1},'审批工号',#{user_id},'审批未通过')                     
WHERE TXN_NO=@{VUCH_NO__old} AND TXN_DT=@{TXN_DT__old} AND EMP_ID=@{EMP_ID__old} AND CLAIM_STATUS_ID='1' ;

UPDATE ibs.T1_FUND_CST_EMP_RELA
