, REMARK=CONCAT(COALESCE(REMARK,''),'审批时间',#{current_time1},'审批工号',#{user_id},'审批未通过')                     
WHERE SERIAL_NO=@{VUCH_NO__old} AND EMP_ID=@{EMP_ID__old} AND TXN_DT=@{TXN_DT__old}  AND CLAIM_STATUS_ID='1';
